def gen(rng, size):
    n = max(3, min(size + 1, 100000))
    center = rng.randrange(1, n + 1)
    leaves = [x for x in range(1, n + 1) if x != center]
    edges = []
    for leaf in leaves:
        if rng.random() < 0.5:
            edges.append([center, leaf])
        else:
            edges.append([leaf, center])
    rng.shuffle(edges)
    return [edges]

